1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  items: Item[];
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_SURCHARGE = 0.1;
13	const CURSE_SURCHARGE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	
17	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const COMPONENT_PREMIUM = 25;
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	const isComponent = (item: Item): boolean =>
30	  COMPONENT_TYPES.includes(item.type);
31	
32	const isMainItem = (item: Item): boolean => !isComponent(item);
33	
34	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
35	// BLOCK_PREMIUM; any other count is priced per component.
36	const componentGroupBasePremium = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
38	
39	// Item-specific surcharges are computed off each affected item's base premium.
40	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
41	const curseSurcharge = (item: Item): number =>
42	  item.cursed ? CURSE_SURCHARGE * basePremiumForItem(item) : 0;
43	
44	// Highly enchanted items (enchantment at or above the threshold) add a
45	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
46	const highEnchantmentSurcharge = (item: Item): number =>
47	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
48	    ? HIGH_ENCHANTMENT_SURCHARGE * basePremiumForItem(item)
49	    : 0;
50	
51	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
52	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
53	// that is only spuriously above a whole number.
54	const roundUpInMHPCOsFavor = (amount: number): number =>
55	  Math.ceil(Number(amount.toFixed(6)));
56	
57	const basePremiumForItem = (item: Item): number =>
58	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
59	
60	// Each main item is priced on its own.
61	const mainItemsBasePremium = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
63	
64	const countByType = (items: Item[]): Map<string, number> => {
65	  const counts = new Map<string, number>();
66	  for (const item of items) {
67	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  }
69	  return counts;
70	};
71	
72	// Components are grouped by type, and each group is block-priced.
73	const componentsBasePremium = (components: Item[]): number =>
74	  [...countByType(components).values()].reduce(
75	    (sum, count) => sum + componentGroupBasePremium(count),
76	    0,
77	  );
78	
79	const policyBasePremium = (items: Item[]): number =>
80	  mainItemsBasePremium(items.filter(isMainItem)) +
81	  componentsBasePremium(items.filter(isComponent));
82	
83	// Tier 1 — item-specific surcharges: computed off each affected item's base
84	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
85	const itemSurcharges = (items: Item[]): number =>
86	  items.reduce(
87	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
88	    0,
89	  );
90	
91	// Tier 2 — policy-wide modifiers: computed as a fraction of the policy base
92	// premium. (e.g. first-insurance surcharge; later loyalty/follow-up discounts.)
93	const policyWideModifiers = (policyBase: number): number =>
94	  FIRST_INSURANCE_SURCHARGE * policyBase;
95	
96	export const quote = (
97	  customer: unknown,
98	  step: QuoteStep,
99	  quoteIndex: number,
100	): number => {
101	  const policyBase = policyBasePremium(step.items);
102	
103	  const total =
104	    policyBase +
105	    itemSurcharges(step.items) +
106	    policyWideModifiers(policyBase) +
107	    PROCESSING_FEE;
108	  return roundUpInMHPCOsFavor(total);
109	};
110	
111	export const claim = (...args: unknown[]): unknown => {
112	  return undefined; // Intentionally not implemented
113	};
